const data = $('Trigger do workflow principal').first().json;
const doctors = $input.all().map(d => d.json).filter(d => d.name);

const msg = (data.messageText || '').trim().toLowerCase();

// Saída: palavras-chave diretas E frases naturais
const exitExact = ['0', 'menu', 'voltar', 'sair', 'tchau', 'obrigado', 'obrigada', 'ok', 'pronto', 'nao', 'não'];
const exitPartial = ['voltar ao menu', 'volta pro menu', 'quero sair', 'encerrar', 'finalizar', 'até mais', 'até logo', 'nada mais', 'é isso', 'isso é tudo', 'mais nada', 'pode fechar', 'encerrando'];
const isExit = exitExact.includes(msg) || exitPartial.some(kw => msg.includes(kw));

// Primeira entrada vindo do menu (dígito único)
const isMenuEntry = /^[1-9]$/.test(msg);

// Intenção de agendamento (detecção antes de chamar a IA)
const schedulingIntent = ['quero agendar', 'gostaria de agendar', 'preciso agendar', 'quero marcar', 'gostaria de marcar', 'preciso marcar', 'marcar consulta', 'agendar consulta', 'fazer uma consulta', 'quero uma consulta', 'posso agendar', 'posso marcar', 'como agendar', 'como marcar', 'gostaria de marcar horário', 'quero marcar horário', 'fazer agendamento', 'disponibilidade', 'horários disponíveis', 'horario disponivel', 'próximo horário', 'proximo horario', 'próxima disponibilidade', 'proxima disponibilidade', 'quando tem vaga', 'tem horário', 'tem horario', 'tem vaga', 'horário livre', 'horario livre', 'próxima vaga', 'proxima vaga', 'agenda disponível', 'agenda disponivel'];
const isSchedulingIntent = !isMenuEntry && !isExit && schedulingIntent.some(kw => msg.includes(kw));

const doctorsList = doctors.length > 0
  ? doctors.map(d => `- ${d.name} (${d.specialty}) - R$ ${d.consultation_price ? Number(d.consultation_price).toFixed(2).replace('.', ',') : 'sob consulta'}`).join('\n')
  : 'Informação não disponível';

const clinicContext = [
  `Nome da clínica: ${data.clinic_name}`,
  `Endereço: ${data.clinic_address || 'Não informado'}`,
  `Horários de funcionamento: ${JSON.stringify(data.clinic_hours || {})}`,
  `Convênios aceitos: ${Array.isArray(data.clinic_insurances) ? data.clinic_insurances.join(', ') : 'Não informado'}`,
  `Médicos e especialidades:\n${doctorsList}`,
  data.extra_info ? `Informações adicionais:\n${data.extra_info}` : ''
].filter(Boolean).join('\n\n');

return [{ json: { ...data, clinicContext, isMenuEntry, isExit, isSchedulingIntent } }];

